"use client";

import { useEffect, useRef, useState } from "react";
import axios from "axios";

const API_URL = process.env.NEXT_PUBLIC_API_URL || "http://localhost:8000";

type Step =
  | "chooseVoice"
  | "chooseDomain"
  | "askName"
  | "askEmail"
  | "askDate"
  | "askTime"
  | "askGuests"
  | "askSection"
  | "askMeal"
  | "confirming"
  | "done";

const voiceMap: Record<string, string> = {
  "1": "shubh",
  "2": "rohan",
  "3": "priya",
  "4": "Kavya",
  "5": "shruti",
};

interface Props {
  open: boolean;
  onClose: () => void;
}

interface Message {
  from: "assistant" | "user";
  text: string;
}

function speak(text: string) {
  if (typeof window === "undefined" || !("speechSynthesis" in window)) return;
  const utter = new SpeechSynthesisUtterance(text);
  utter.rate = 1;
  utter.pitch = 1;
  window.speechSynthesis.cancel();
  window.speechSynthesis.speak(utter);
}

export function VoiceAssistantModal({ open, onClose }: Props) {
  const [step, setStep] = useState<Step>("chooseVoice");
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState("");
  const [selectedVoice, setSelectedVoice] = useState<string | null>(null);
  const [domain, setDomain] = useState<string | null>(null);

  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [date, setDate] = useState("");
  const [time, setTime] = useState("");
  const [people, setPeople] = useState<number | null>(null);
  const [section, setSection] = useState<"AC" | "Non-AC" | null>(null);
  const [duration, setDuration] = useState<"breakfast" | "lunch" | "dinner" | null>(null);

  const bottomRef = useRef<HTMLDivElement | null>(null);
  const recognitionRef = useRef<any | null>(null);
  const [listening, setListening] = useState(false);
  const [speechSupported, setSpeechSupported] = useState(false);

  useEffect(() => {
    if (!open) return;
    // Reset state when opened
    setStep("chooseVoice");
    setMessages([
      {
        from: "assistant",
        text:
          "Welcome to Aurora's voice assistant. Please choose a voice by typing a number: 1) shubh (Male), 2) rohan (Male), 3) priya (Female), 4) Kavya (Female), 5) shruti (Female).",
      },
    ]);
    setInput("");
    setSelectedVoice(null);
    setDomain(null);
    setName("");
    setEmail("");
    setDate("");
    setTime("");
    setPeople(null);
    setSection(null);
    setDuration(null);
    speak(
      "Welcome to Aurora's voice assistant. Please choose a voice: shubh, rohan, priya, Kavya, or shruti.",
    );

    // Setup speech recognition if available
    if (typeof window !== "undefined") {
      const SR: any =
        (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
      if (SR) {
        const recog = new SR();
        recog.lang = "en-US";
        recog.interimResults = false;
        recog.maxAlternatives = 1;
        recog.onresult = (event: any) => {
          const transcript = event.results?.[0]?.[0]?.transcript?.trim();
          if (transcript) {
            processUserInput(transcript);
          }
        };
        recog.onend = () => {
          setListening(false);
        };
        recognitionRef.current = recog;
        setSpeechSupported(true);
      } else {
        recognitionRef.current = null;
        setSpeechSupported(false);
      }
    }
  }, [open]);

  useEffect(() => {
    if (bottomRef.current) {
      bottomRef.current.scrollIntoView({ behavior: "smooth" });
    }
  }, [messages]);

  if (!open) return null;

  const pushAssistant = (text: string, nextStep?: Step) => {
    setMessages((prev) => [...prev, { from: "assistant", text }]);
    speak(text);
    if (nextStep) setStep(nextStep);
  };

  const processUserInput = async (rawText: string) => {
    const trimmed = rawText.trim();
    if (!trimmed) return;

    setMessages((prev) => [...prev, { from: "user", text: trimmed }]);

    if (step === "chooseVoice") {
      const key = trimmed;
      const voice = voiceMap[key];
      if (!voice) {
        pushAssistant("I didn't catch that. Please choose a number between 1 and 5 for the voice.");
        return;
      }
      setSelectedVoice(voice);
      pushAssistant(
        `Great, I will speak as ${voice}. Now, please choose what you need help with: type 1 for ecommerce support, 2 for car booking, or 3 for restaurant table booking.`,
        "chooseDomain",
      );
      return;
    }

    if (step === "chooseDomain") {
      if (["1", "2"].includes(trimmed)) {
        setDomain(trimmed === "1" ? "ecommerce" : "car_booking");
        pushAssistant(
          "At the moment, voice ordering is available only for restaurant table booking. Please type 3 if you want to book a table.",
        );
        return;
      }

      if (trimmed === "3") {
        setDomain("restaurant");
        pushAssistant("Wonderful. Let's book your table. First, may I have your full name?", "askName");
        return;
      }

      pushAssistant(
        "I didn't understand that. Please type 1 for ecommerce, 2 for car booking, or 3 for restaurant table booking.",
      );
      return;
    }

    if (step === "askName") {
      setName(trimmed);
      pushAssistant("Thank you. What email address should we use for your reservation?", "askEmail");
      return;
    }

    if (step === "askEmail") {
      setEmail(trimmed);
      pushAssistant("On which date would you like to dine? Please type in YYYY-MM-DD format.", "askDate");
      return;
    }

    if (step === "askDate") {
      setDate(trimmed);
      pushAssistant(
        "At what time would you like the reservation? Please type in HH:MM, for example 19:30.",
        "askTime",
      );
      return;
    }

    if (step === "askTime") {
      setTime(trimmed);
      pushAssistant("How many guests will be joining, including you?", "askGuests");
      return;
    }

    if (step === "askGuests") {
      const n = Number(trimmed);
      if (!Number.isFinite(n) || n <= 0) {
        pushAssistant("Please enter a valid number of guests.");
        return;
      }
      setPeople(n);
      pushAssistant(
        "Do you prefer AC or Non-AC section? Please type AC or Non-AC.",
        "askSection",
      );
      return;
    }

    if (step === "askSection") {
      const value = trimmed.toLowerCase();
      if (value === "ac" || value === "a.c" || value === "a c") {
          setSection("AC");
      } else if (value === "non-ac" || value === "non ac") {
          setSection("Non-AC");
      } else {
          pushAssistant("Please type AC or Non-AC.");
        return;
      }
      pushAssistant(
        "Finally, which meal slot would you like? Type breakfast, lunch, or dinner.",
        "askMeal",
      );
      return;
    }

    if (step === "askMeal") {
      const value = trimmed.toLowerCase();
      if (!["breakfast", "lunch", "dinner"].includes(value)) {
          pushAssistant("Please type breakfast, lunch, or dinner.");
        return;
      }
      setDuration(value as "breakfast" | "lunch" | "dinner");

      pushAssistant(
        "Perfect. Let me place your reservation now. One moment please.",
        "confirming",
      );

      try {
        await axios.post(`${API_URL}/restaurant/reserve`, {
          name,
          email: email || "not_provided@aurora.com",
          date,
          time,
          people: people ?? 2,
          section: section ?? "AC",
          duration: value,
        });

        pushAssistant(
          `Your table has been reserved successfully for ${people ?? 2} guests on ${date} at ${time}. We look forward to welcoming you at Aurora Dining.`,
          "done",
        );
      } catch (err) {
        pushAssistant(
          "Something went wrong while placing your reservation. Please try again or use the regular form.",
          "done",
        );
      }
      return;
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const trimmed = input.trim();
    if (!trimmed) return;
    setInput("");
    await processUserInput(trimmed);
  };

  const toggleMic = () => {
    if (!speechSupported || !recognitionRef.current) return;
    if (listening) {
      recognitionRef.current.stop();
      return;
    }
    try {
      setListening(true);
      recognitionRef.current.start();
    } catch {
      setListening(false);
    }
  };

  return (
    <div
      style={{
        position: "fixed",
        inset: 0,
        zIndex: 200,
        backgroundColor: "rgba(0,0,0,0.6)",
        backdropFilter: "blur(10px)",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        padding: "24px",
      }}
    >
      <div
        className="surface"
        style={{
          maxWidth: "640px",
          width: "100%",
          maxHeight: "80vh",
          borderRadius: "16px",
          padding: "20px 20px 16px",
          display: "flex",
          flexDirection: "column",
        }}
      >
        <div
          style={{
            display: "flex",
            alignItems: "center",
            justifyContent: "space-between",
            marginBottom: "12px",
          }}
        >
          <h2
            style={{
              fontFamily: "'Cormorant Garamond', serif",
              fontSize: "24px",
              fontWeight: 300,
            }}
          >
            Aurora Voice Assistant
          </h2>
          <div style={{ display: "flex", alignItems: "center", gap: "8px" }}>
            {speechSupported && (
              <button
                type="button"
                onClick={toggleMic}
                style={{
                  background: listening ? "rgba(201,169,110,0.22)" : "transparent",
                  border: "1px solid rgba(201,169,110,0.4)",
                  borderRadius: "999px",
                  padding: "4px 10px",
                  color: "var(--color-text)",
                  fontSize: "11px",
                  letterSpacing: "0.12em",
                  textTransform: "uppercase",
                  cursor: "pointer",
                }}
              >
                {listening ? "Listening…" : "Tap to Speak"}
              </button>
            )}
            <button
              onClick={onClose}
              style={{
                background: "transparent",
                border: "none",
                color: "var(--color-muted)",
                fontSize: "18px",
                cursor: "pointer",
              }}
              aria-label="Close"
            >
              ×
            </button>
          </div>
        </div>

        <div
          style={{
            fontSize: "13px",
            color: "var(--color-muted)",
            marginBottom: "8px",
          }}
        >
          {selectedVoice && (
            <span>
              Voice: <strong>{selectedVoice}</strong>
              {domain && domain === "restaurant" && " • Restaurant booking"}
            </span>
          )}
        </div>

        <div
          style={{
            flex: 1,
            overflowY: "auto",
            padding: "12px 4px 8px",
            marginBottom: "12px",
            borderRadius: "8px",
          }}
        >
          {messages.map((m, idx) => (
            <div
              key={idx}
              style={{
                marginBottom: "10px",
                textAlign: m.from === "assistant" ? "left" : "right",
              }}
            >
              <div
                style={{
                  display: "inline-block",
                  padding: "8px 10px",
                  borderRadius: "10px",
                  backgroundColor:
                    m.from === "assistant"
                      ? "rgba(17,17,17,0.9)"
                      : "rgba(201,169,110,0.16)",
                  color: "var(--color-text)",
                  fontSize: "14px",
                  maxWidth: "100%",
                  whiteSpace: "pre-wrap",
                }}
              >
                {m.text}
              </div>
            </div>
          ))}
          <div ref={bottomRef} />
        </div>

        <form
          onSubmit={handleSubmit}
          style={{
            display: "flex",
            gap: "8px",
            marginTop: "4px",
          }}
        >
          <input
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Type your answer here and press Enter..."
            style={{
              flex: 1,
              padding: "10px 12px",
              borderRadius: "999px",
              border: "1px solid rgba(201,169,110,0.35)",
              background: "transparent",
              color: "var(--color-text)",
              fontSize: "14px",
            }}
          />
          <button
            type="submit"
            className="btn-gold"
            style={{
              padding: "10px 20px",
              fontSize: "12px",
              letterSpacing: "0.12em",
            }}
          >
            Send
          </button>
        </form>
      </div>
    </div>
  );
}

